mapper.select:
SELECT 
FROM im_invite_code_usage_log

    deleted = 0

        AND invite_code_id = #{ew.inviteCodeId}


        AND invite_code LIKE CONCAT('%', #{ew.inviteCode}, '%')


        AND tenant_id = #{ew.tenantId}


        AND tenant_name LIKE CONCAT('%', #{ew.tenantName}, '%')


        AND user_id = #{ew.userId}


        AND user_name LIKE CONCAT('%', #{ew.userName}, '%')


        AND user_ip LIKE CONCAT('%', #{ew.userIp}, '%')


        AND device_type = #{ew.deviceType}


        AND usage_result = #{ew.usageResult}


        AND usage_time BETWEEN #{ew.usageTime[0]} AND #{ew.usageTime[1]}


ORDER BY usage_time DESC
